#include<bits/stdc++.h>
using namespace std;
pair<int, int>p[1000006];
int main()
{
	int n;
	cin >> n;
	for(int i = 1; i <= n; i++){
		int x;
		cin >> x;
		p[i] = {x, i};
	}
	sort(p + 1, p + n + 1);
	double time = 0;
	for(int i = 1;  i <= n; i++){
		cout << p[i].second << " ";
		time += (n - i) * p[i].first; 
	}
	cout << endl;
	printf("%.2f", time / n);
}
